import{_ as e,o as l,c as i,a9 as r}from"./chunks/framework.STMWz9Nm.js";const m=JSON.parse('{"title":"查询DSL与聚合分析","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/11-ElasticSearch学习/03-查询DSL与聚合分析.md","filePath":"语言/java/11-ElasticSearch学习/03-查询DSL与聚合分析.md","lastUpdated":1776149370000}'),t={name:"语言/java/11-ElasticSearch学习/03-查询DSL与聚合分析.md"};function h(_,a,n,s,c,o){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="查询dsl与聚合分析" tabindex="-1">查询DSL与聚合分析 <a class="header-anchor" href="#查询dsl与聚合分析" aria-label="Permalink to “查询DSL与聚合分析”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>查询 DSL 是 ElasticSearch 描述搜索条件的结构化方式，聚合用于做统计、分组和分析。<br> 它们共同构成了 ES 最常用的业务能力。</p><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>ES 不只是搜索引擎，也是分析引擎。<br> 学会查询和聚合，才能把搜索、筛选、统计和报表结合起来。</p><h2 id="_3-核心内容" tabindex="-1">3. 核心内容 <a class="header-anchor" href="#_3-核心内容" aria-label="Permalink to “3. 核心内容”">​</a></h2><ul><li>match、term、range</li><li>bool query</li><li>filter 与 score</li><li>sort 与分页</li><li>terms aggregation、metric aggregation</li></ul><h2 id="_4-学习重点" tabindex="-1">4. 学习重点 <a class="header-anchor" href="#_4-学习重点" aria-label="Permalink to “4. 学习重点”">​</a></h2><ul><li>理解 query 和 filter 的差异</li><li>理解相关性评分和精确过滤的边界</li><li>理解聚合会带来额外计算成本</li></ul><h2 id="_5-常见问题" tabindex="-1">5. 常见问题 <a class="header-anchor" href="#_5-常见问题" aria-label="Permalink to “5. 常见问题”">​</a></h2><ul><li>把所有条件都放 query</li><li>不清楚 match 和 term 的适用差异</li><li>聚合用多了却不评估性能代价</li></ul><h2 id="_6-练习建议" tabindex="-1">6. 练习建议 <a class="header-anchor" href="#_6-练习建议" aria-label="Permalink to “6. 练习建议”">​</a></h2><ul><li>为商品列表实现搜索 + 筛选 + 排序</li><li>写几个常见聚合统计例子</li><li>对比 filter 和 query 的查询效果</li></ul><h2 id="_7-自测问题" tabindex="-1">7. 自测问题 <a class="header-anchor" href="#_7-自测问题" aria-label="Permalink to “7. 自测问题”">​</a></h2><ul><li>match 和 term 分别适合什么查询</li><li>filter 为什么通常更适合精确条件</li><li>聚合为什么既强大又昂贵</li></ul>',15)])])}const f=e(t,[["render",h]]);export{m as __pageData,f as default};
